import React, { useEffect, useState } from "react";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო უკეთ გაიცნო შენი შესაძლებლობები?",
  ESFJ: "გამარჯობა 💛 გინდა ვისაუბროთ შენს ურთიერთობებსა და მიზნებზე?",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო, რომ უკეთ გაიცნო შენი ფსიქოტიპი?"
};

export default function PersonalAIMentor({ userType }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");

  const mbti = userType || "DEFAULT";
  const storageKey = "ai_chat_history_" + mbti;

  // ✅ ჩატის აღდგენა
  useEffect(() => {
    const saved = localStorage.getItem(storageKey);

    if (saved) {
      setMessages(JSON.parse(saved));
    } else {
      const first = firstMessages[mbti] || firstMessages.DEFAULT;
      setMessages([{ role: "ai", text: first }]);
    }
  }, [mbti]);

  // ✅ ჩატის შენახვა
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem(storageKey, JSON.stringify(messages));
    }
  }, [messages, storageKey]);

  const sendMessage = () => {
    if (!input.trim()) return;

    const newUserMsg = { role: "user", text: input };
    setMessages(prev => [...prev, newUserMsg]);

    fetch("http://localhost:5000/api/chat-reply", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        message: input,
        type: mbti,
        history: messages.slice(-10)
      })
    })
      .then(res => res.json())
      .then(data => {
        setMessages(prev => [...prev, { role: "ai", text: data.reply }]);
      })
      .catch(() => {
        setMessages(prev => [
          ...prev,
          { role: "ai", text: "უკაცრავად, ახლა ჩატი ხელმისაწვდომი არ არის 😅" }
        ]);
      });

    setInput("");
  };

  // ✅ New Chat
  const newChat = () => {
    localStorage.removeItem(storageKey);
    const first = firstMessages[mbti] || firstMessages.DEFAULT;
    setMessages([{ role: "ai", text: first }]);
  };

  return (
    <div className="ai-mentor">
      <div className="ai-header">
        Personal AI Mentor
        <button className="new-chat-btn" onClick={newChat}>
          New Chat
        </button>
      </div>

      <div className="ai-messages">
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            {m.text}
          </div>
        ))}
      </div>

      <div className="ai-input">
        <textarea
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
          placeholder="მომწერე..."
          rows="1"
          className="ai-textarea"
        />

        <button onClick={sendMessage}>გაგზავნა</button>
      </div>
    </div>
  );
}
